    title: "Coordinated Multi-Partner Reproductive Optimization System with AI-Driven Joint Intervention Planning",
    shortTitle: "Partner Fertility Coordination",
    status: "draft",
    patentRef: "US-APP-2026-PENDING",
    category: "software_ai",
